     public void GenerateSlug_Result_ContainsOnlySlugCharacters()
     {
         var result = _formatter.GenerateSlug("Hello, World! #2024");

         Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
     }

     [TestMethod]
     public void GenerateSlug_MixedCase_ProducesLowercaseResult()
     {
         var result = _formatter.GenerateSlug("UPPER Case Title");

         Assert.AreEqual("upper-case-title", result);
     }

     [TestMethod]
     public void GenerateSlug_Null_ThrowsArgumentNullException()
     {
         Assert.ThrowsExactly<ArgumentNullException>(
             () => _formatter.GenerateSlug(null!));
     }

     [TestMethod]
     [DataRow("")]
     [DataRow("   ")]
     public void GenerateSlug_WhiteSpace_ThrowsArgumentException(string title)
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _formatter.GenerateSlug(title));
     }

